   280→ValidationResults DefaultCertValidator::doVerifyCertChain(
   281→    STACK_OF(X509)& cert_chain, Ssl::ValidateResultCallbackPtr /*callback*/,
   282→    const Network::TransportSocketOptionsConstSharedPtr& transport_socket_options, SSL_CTX& ssl_ctx,
   283→    const CertValidator::ExtraValidationContext& /*validation_context*/, bool is_server,
   284→    absl::string_view /*host_name*/) {
   285→  if (sk_X509_num(&cert_chain) == 0) {
   286→    stats_.fail_verify_error_.inc();
   287→    const char* error = "verify cert failed: empty cert chain";
   288→    ENVOY_LOG(debug, error);
   289→    return {ValidationResults::ValidationStatus::Failed,
   290→            Envoy::Ssl::ClientValidationStatus::NoClientCertificate, absl::nullopt, error};
   291→  }
   292→  Envoy::Ssl::ClientValidationStatus detailed_status =
   293→      Envoy::Ssl::ClientValidationStatus::NotValidated;
   294→  X509* leaf_cert = sk_X509_value(&cert_chain, 0);
   295→  ASSERT(leaf_cert);
   296→  if (verify_trusted_ca_) {
   297→    X509_STORE* verify_store = SSL_CTX_get_cert_store(&ssl_ctx);
   298→    ASSERT(verify_store);
   299→    bssl::UniquePtr<X509_STORE_CTX> ctx(X509_STORE_CTX_new());
   300→    if (!ctx || !X509_STORE_CTX_init(ctx.get(), verify_store, leaf_cert, &cert_chain) ||
   301→        // We need to inherit the verify parameters. These can be determined by
   302→        // the context: if it's a server it will verify SSL client certificates or
   303→        // vice versa.
   304→        !X509_STORE_CTX_set_default(ctx.get(), is_server ? "ssl_client" : "ssl_server") ||
   305→        // Anything non-default in "param" should overwrite anything in the ctx.
   306→        !X509_VERIFY_PARAM_set1(X509_STORE_CTX_get0_param(ctx.get()),
   307→                                SSL_CTX_get0_param(&ssl_ctx))) {
   308→      OPENSSL_PUT_ERROR(SSL, ERR_R_X509_LIB);
   309→      const char* error = "verify cert failed: init and setup X509_STORE_CTX";
   310→      stats_.fail_verify_error_.inc();
   311→      ENVOY_LOG(debug, error);
   312→      return {ValidationResults::ValidationStatus::Failed,
   313→              Envoy::Ssl::ClientValidationStatus::Failed, absl::nullopt, error};
   314→    }
   315→    const bool verify_succeeded = (X509_verify_cert(ctx.get()) == 1);
   316→
   317→    if (!verify_succeeded) {
   318→      const std::string error =
   319→          absl::StrCat("verify cert failed: ", Utility::getX509VerificationErrorInfo(ctx.get()));
   320→      stats_.fail_verify_error_.inc();
   321→      ENVOY_LOG(debug, error);
   322→      if (allow_untrusted_certificate_) {
   323→        return ValidationResults{ValidationResults::ValidationStatus::Successful,
   324→                                 Envoy::Ssl::ClientValidationStatus::Failed, absl::nullopt,
   325→                                 absl::nullopt};
   326→      }
   327→      return {ValidationResults::ValidationStatus::Failed,
   328→              Envoy::Ssl::ClientValidationStatus::Failed,
   329→              SSL_alert_from_verify_result(X509_STORE_CTX_get_error(ctx.get())), error};
   330→    }
   331→    detailed_status = Envoy::Ssl::ClientValidationStatus::Validated;
   332→  }
   333→  std::string error_details;
   334→  uint8_t tls_alert = SSL_AD_CERTIFICATE_UNKNOWN;
   335→  const bool succeeded = verifyCertAndUpdateStatus(leaf_cert, transport_socket_options.get(),
   336→                                                   detailed_status, &error_details, &tls_alert);
   337→  return succeeded ? ValidationResults{ValidationResults::ValidationStatus::Successful,
   338→                                       detailed_status, absl::nullopt, absl::nullopt}
   339→                   : ValidationResults{ValidationResults::ValidationStatus::Failed, detailed_status,
   340→                                       tls_alert, error_details};
   341→}
