   418→void DefaultCertValidator::updateDigestForSessionId(bssl::ScopedEVP_MD_CTX& md,
   419→                                                    uint8_t hash_buffer[EVP_MAX_MD_SIZE],
   420→                                                    unsigned hash_length) {
   421→  int rc;
   422→
   423→  // Hash all the settings that affect whether the server will allow/accept
   424→  // the client connection. This ensures that the client is always validated against
   425→  // the correct settings, even if session resumption across different listeners
   426→  // is enabled.
   427→  if (ca_cert_ != nullptr) {
   428→    rc = X509_digest(ca_cert_.get(), EVP_sha256(), hash_buffer, &hash_length);
   429→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   430→    RELEASE_ASSERT(hash_length == SHA256_DIGEST_LENGTH,
   431→                   fmt::format("invalid SHA256 hash length {}", hash_length));
   432→
   433→    rc = EVP_DigestUpdate(md.get(), hash_buffer, hash_length);
   434→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   435→  }
   436→
   437→  for (const auto& hash : verify_certificate_hash_list_) {
   438→    rc = EVP_DigestUpdate(md.get(), hash.data(),
   439→                          hash.size() *
   440→                              sizeof(std::remove_reference<decltype(hash)>::type::value_type));
   441→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   442→  }
   443→
   444→  for (const auto& hash : verify_certificate_spki_list_) {
   445→    rc = EVP_DigestUpdate(md.get(), hash.data(),
   446→                          hash.size() *
   447→                              sizeof(std::remove_reference<decltype(hash)>::type::value_type));
   448→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   449→  }
   450→
   451→  rc = EVP_DigestUpdate(md.get(), &verify_trusted_ca_, sizeof(verify_trusted_ca_));
   452→  RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   453→
   454→  if (config_ != nullptr) {
   455→    for (const auto& matcher : config_->subjectAltNameMatchers()) {
   456→      size_t hash = MessageUtil::hash(matcher);
   457→      rc = EVP_DigestUpdate(md.get(), &hash, sizeof(hash));
   458→      RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   459→    }
   460→
   461→    const std::string& crl = config_->certificateRevocationList();
   462→    if (!crl.empty()) {
   463→      rc = EVP_DigestUpdate(md.get(), crl.data(), crl.length());
   464→      RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   465→    }
   466→
   467→    bool allow_expired = config_->allowExpiredCertificate();
   468→    rc = EVP_DigestUpdate(md.get(), &allow_expired, sizeof(allow_expired));
   469→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   470→
   471→    auto trust_chain_verification = config_->trustChainVerification();
   472→    rc = EVP_DigestUpdate(md.get(), &trust_chain_verification, sizeof(trust_chain_verification));
   473→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   474→
   475→    auto only_leaf_crl = config_->onlyVerifyLeafCertificateCrl();
   476→    rc = EVP_DigestUpdate(md.get(), &only_leaf_crl, sizeof(only_leaf_crl));
   477→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   478→  }
   479→}
