   244→bool SPIFFEValidator::certificatePrecheck(X509* leaf_cert) {
   245→  // Check basic constrains and key usage.
   246→  // https://github.com/spiffe/spiffe/blob/master/standards/X509-SVID.md#52-leaf-validation
   247→  const auto ext = X509_get_extension_flags(leaf_cert);
   248→  if (ext & EXFLAG_CA) {
   249→    return false;
   250→  }
   251→
   252→  const auto us = X509_get_key_usage(leaf_cert);
   253→  return (us & (KU_CRL_SIGN | KU_KEY_CERT_SIGN)) == 0;
   254→}
   255→
   256→bool SPIFFEValidator::matchSubjectAltName(X509& leaf_cert) {
   257→  bssl::UniquePtr<GENERAL_NAMES> san_names(static_cast<GENERAL_NAMES*>(
   258→      X509_get_ext_d2i(&leaf_cert, NID_subject_alt_name, nullptr, nullptr)));
   259→  // We must not have san_names == nullptr here because this function is called after the
   260→  // SPIFFE cert validation algorithm succeeded, which requires exactly one URI SAN in the leaf
   261→  // cert.
   262→  ASSERT(san_names != nullptr,
   263→         "san_names should have at least one name after SPIFFE cert validation");
   264→
   265→  for (const GENERAL_NAME* general_name : san_names.get()) {
   266→    for (const auto& config_san_matcher : subject_alt_name_matchers_) {
   267→      if (config_san_matcher->match(general_name)) {
   268→        return true;
   269→      }
   270→    }
   271→  }
   272→  return false;
   273→}
