   275→std::string SPIFFEValidator::extractTrustDomain(const std::string& san) {
   276→  static const std::string prefix = "spiffe://";
   277→  if (!absl::StartsWith(san, prefix)) {
   278→    return "";
   279→  }
   280→
   281→  auto pos = san.find('/', prefix.size());
   282→  if (pos != std::string::npos) {
   283→    return san.substr(prefix.size(), pos - prefix.size());
   284→  }
   285→  return "";
   286→}
