    59→                                     Server::Configuration::CommonFactoryContext& factory_context,
    60→                                     absl::Status& creation_status)
    61→    : ContextImpl(scope, config, factory_context, nullptr /* additional_init */, creation_status),
    62→      server_name_indication_(config.serverNameIndication()),
    63→      allow_renegotiation_(config.allowRenegotiation()),
    64→      enforce_rsa_key_usage_(config.enforceRsaKeyUsage()),
    65→      max_session_keys_(config.maxSessionKeys()) {
