    93→ClientContextImpl::newSsl(const Network::TransportSocketOptionsConstSharedPtr& options) {
    94→  absl::StatusOr<bssl::UniquePtr<SSL>> ssl_con_or_status(ContextImpl::newSsl(options));
    95→  if (!ssl_con_or_status.ok()) {
    96→    return ssl_con_or_status;
    97→  }
    98→
    99→  bssl::UniquePtr<SSL> ssl_con = std::move(ssl_con_or_status.value());
   100→
   101→  const std::string server_name_indication = options && options->serverNameOverride().has_value()
   102→                                                 ? options->serverNameOverride().value()
   103→                                                 : server_name_indication_;
   104→  if (!server_name_indication.empty()) {
   105→    const int rc = SSL_set_tlsext_host_name(ssl_con.get(), server_name_indication.c_str());
   106→    if (rc != 1) {
   107→      return absl::InvalidArgumentError(
   108→          absl::StrCat("Failed to create upstream TLS due to failure setting SNI: ",
   109→                       Utility::getLastCryptoError().value_or("unknown")));
   110→    }
   111→  }
   112→
   113→  if (options && !options->verifySubjectAltNameListOverride().empty()) {
   114→    SSL_set_verify(ssl_con.get(), SSL_VERIFY_PEER | SSL_VERIFY_FAIL_IF_NO_PEER_CERT, nullptr);
   115→  }
   116→
   117→  // We determine what ALPN using the following precedence:
   118→  // 1. Option-provided ALPN override.
   119→  // 2. ALPN statically configured in the upstream TLS context.
   120→  // 3. Option-provided ALPN fallback.
   121→
   122→  // At this point in the code the ALPN has already been set (if present) to the value specified in
   123→  // the TLS context. We've stored this value in parsed_alpn_protocols_ so we can check that to see
   124→  // if it's already been set.
   125→  bool has_alpn_defined = !parsed_alpn_protocols_.empty();
   126→  absl::Status parse_status = absl::OkStatus();
   127→  if (options) {
   128→    // ALPN override takes precedence over TLS context specified, so blindly overwrite it.
   129→    has_alpn_defined |=
   130→        parseAndSetAlpn(options->applicationProtocolListOverride(), *ssl_con, parse_status);
   131→  }
   132→
   133→  if (options && !has_alpn_defined && !options->applicationProtocolFallback().empty()) {
   134→    // If ALPN hasn't already been set (either through TLS context or override), use the fallback.
   135→    parseAndSetAlpn(options->applicationProtocolFallback(), *ssl_con, parse_status);
   136→  }
   137→  RETURN_IF_NOT_OK(parse_status);
   138→
   139→  if (allow_renegotiation_) {
   140→    SSL_set_renegotiate_mode(ssl_con.get(), ssl_renegotiate_freely);
   141→  }
   142→
   143→  SSL_set_enforce_rsa_key_usage(ssl_con.get(), enforce_rsa_key_usage_);
   144→
   145→  if (max_session_keys_ > 0) {
   146→    if (session_keys_single_use_) {
   147→      // Stored single-use session keys, use write/write locks.
   148→      absl::WriterMutexLock l(&session_keys_mu_);
   149→      if (!session_keys_.empty()) {
   150→        // Use the most recently stored session key, since it has the highest
   151→        // probability of still being recognized/accepted by the server.
   152→        SSL_SESSION* session = session_keys_.front().get();
   153→        SSL_set_session(ssl_con.get(), session);
   154→        // Remove single-use session key (TLS 1.3) after first use.
   155→        if (SSL_SESSION_should_be_single_use(session)) {
   156→          session_keys_.pop_front();
   157→        }
   158→      }
   159→    } else {
   160→      // Never stored single-use session keys, use read/write locks.
   161→      absl::ReaderMutexLock l(&session_keys_mu_);
   162→      if (!session_keys_.empty()) {
   163→        // Use the most recently stored session key, since it has the highest
   164→        // probability of still being recognized/accepted by the server.
   165→        SSL_SESSION* session = session_keys_.front().get();
   166→        SSL_set_session(ssl_con.get(), session);
   167→      }
   168→    }
   169→  }
   170→
   171→  return ssl_con;
   172→}
