   174→int ClientContextImpl::newSessionKey(SSL_SESSION* session) {
   175→  // In case we ever store single-use session key (TLS 1.3),
   176→  // we need to switch to using write/write locks.
   177→  if (SSL_SESSION_should_be_single_use(session)) {
   178→    session_keys_single_use_ = true;
   179→  }
   180→  absl::WriterMutexLock l(&session_keys_mu_);
   181→  // Evict oldest entries.
   182→  while (session_keys_.size() >= max_session_keys_) {
   183→    session_keys_.pop_back();
   184→  }
   185→  // Add new session key at the front of the queue, so that it's used first.
   186→  session_keys_.push_front(bssl::UniquePtr<SSL_SESSION>(session));
   187→  return 1; // Tell BoringSSL that we took ownership of the session.
   188→}
